'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { classifySequence } = require('../src/serialOrder');
const { Replica } = require('../src/replica');

test('serial classification distinguishes wrapped progress from delayed traffic', () => {
  assert.deepEqual(classifySequence(65534, 1), { kind: 'forward', distance: 3 });
  assert.equal(classifySequence(1, 65534).kind, 'stale');
  assert.equal(classifySequence(22000, 22000).kind, 'duplicate');
});

test('replica advances across a run and rejects a delayed pre-rollover frame', () => {
  const replica = new Replica();
  for (const frame of [
    { sequence: 65534, value: 'a' },
    { sequence: 65535, value: 'b' },
    { sequence: 0, value: 'c' },
    { sequence: 1, value: 'd' },
  ]) {
    assert.equal(replica.accept(frame), true);
  }
  assert.equal(replica.accept({ sequence: 65535, value: 'delayed' }), false);
  assert.deepEqual(replica.current, { sequence: 1, value: 'd' });
});
